// Interface: contract

interface Serializable { serialize(): string; deserialize(s: string): void; }

interface Printable { print(): void; }

// Abstract class: base behavior

abstract class BaseEntity {

  readonly id: string = crypto.randomUUID();

  readonly createdAt: Date = new Date();

  abstract validate(): boolean; // subclass must implement

  toJSON(): object { return { id: this.id, createdAt: this.createdAt }; }

  }

// Combine: abstract class + interface

class User extends BaseEntity implements Serializable, Printable {

  constructor(public name: string, public email: string) { super(); }

  validate() { return !!this.email.includes('@'); }

  serialize() { return JSON.stringify({ name: this.name, email: this.email }); }

  deserialize(s: string) { const d = JSON.parse(s); this.name = d.name; }

  print() { console.log(`User: ${this.name}`); }

  }

An interface defines a pure contract (what a class must do), while an abstract class provides a partial base implementation with shared behaviour (how some things are done). In TypeScript, a class can implement multiple interfaces but can only extend one abstract class.

**Interface: ****No implementation (TypeScript allows optional default methods); supports multiple inheritance; all members are public by default; use for defining contracts and multiple type shapes.**

**Abstract class: ****Can have concrete methods and instance fields; supports constructors and access modifiers; only single inheritance; use when classes share common behaviour.**

**Best practice: ****Prefer interface for contracts and abstract class for shared base logic — combine both freely (class User extends BaseEntity implements Serializable).**

