abstract class Repository<T, ID> {

  // Abstract: subclass phải implement

  abstract findById(id: ID): Promise<T | null>;

  abstract findAll(): Promise<T[]>;

  abstract save(entity: T): Promise<T>;

  abstract delete(id: ID): Promise<void>;

  // Concrete: áp dụng chung cho mọi subclass

  async findOrThrow(id: ID): Promise<T> {

    const entity = await this.findById(id);

    if (!entity) throw new Error(`Entity ${id} not found`);

    return entity;

  }

  async saveAll(entities: T[]): Promise<T[]> {

    return Promise.all(entities.map(e => this.save(e)));

  }

  }

class UserRepository extends Repository<User, number> {

  async findById(id: number): Promise<User | null> {

    return db.query('SELECT * FROM users WHERE id = ?', [id]);

  }

  // ... implement remaining abstract methods

  }

class QueryBuilder {

  private table  = '';

  private wheres: string[] = [];

  private orderBy = '';

  private limitVal = 0;

  from(table: string): this { this.table = table; return this; }

  where(cond: string):  this { this.wheres.push(cond); return this; }

  order(col: string):   this { this.orderBy = col; return this; }

  limit(n: number):     this { this.limitVal = n; return this; }

  build(): string {

    let q = `SELECT * FROM ${this.table}`;

    if (this.wheres.length) q += ` WHERE ${this.wheres.join(' AND ')}`;

    if (this.orderBy) q += ` ORDER BY ${this.orderBy}`;

    if (this.limitVal) q += ` LIMIT ${this.limitVal}`;

    return q;

  }

  }

const sql = new QueryBuilder()

  .from('users')

  .where('age > 18')

  .where('active = true')

  .order('name')

  .limit(10)

  .build();

class Address {

  constructor(public city: string, public country: string) {}

  // Shallow clone

  shallowClone(): Address { return Object.assign(new Address('',''), this); }

  // Deep clone

  deepClone(): Address { return new Address(this.city, this.country); }

  }

class Person {

  constructor(

    public name: string,

    public address: Address

  ) {}

  shallowClone(): Person {

    // address là same reference!

    return new Person(this.name, this.address);

  }

  deepClone(): Person {

    return new Person(this.name, this.address.deepClone());

  }

  }

const p1 = new Person('Dat', new Address('HCM', 'VN'));

const shallow = p1.shallowClone();

shallow.address.city = 'HN';

console.log(p1.address.city); // 'HN' (bị thay đổi!)

const deep = p1.deepClone();

deep.address.city = 'DN';

console.log(p1.address.city); // 'HCM' (an toàn)

type Constructor<T = {}> = new (...args: any[]) => T;

// Mixin functions

function Timestamped<TBase extends Constructor>(Base: TBase) {

  return class extends Base {

    createdAt = new Date();

    updatedAt = new Date();

    touch() { this.updatedAt = new Date(); }

  };

  }

function SoftDeletable<TBase extends Constructor>(Base: TBase) {

  return class extends Base {

    deletedAt: Date | null = null;

    softDelete() { this.deletedAt = new Date(); }

    isDeleted() { return this.deletedAt !== null; }

  };

  }

class BaseModel { constructor(public id: number) {} }

// Compose mixins

const TimestampedDeletable = SoftDeletable(Timestamped(BaseModel));

class Post extends TimestampedDeletable {

  constructor(id: number, public title: string) { super(id); }

  }

const post = new Post(1, 'Hello World');

post.touch();

post.softDelete();

