// Objects communicate via method calls

class Order {

  constructor(

    private items: OrderItem[],

    private payment: PaymentService,

    private notifier: NotificationService

  ) {}

  async checkout(): Promise<void> {

    const total = this.items.reduce((sum, i) => sum + i.price, 0);

    await this.payment.charge(total);    // message to PaymentService

    await this.notifier.notify('Order confirmed');  // message to Notifier

  }

  }

// Observer pattern: message broadcasting

class EventEmitter<T> {

  private listeners = new Map<string, ((data: T) => void)[]>();

  on(event: string, fn: (data: T) => void) { (this.listeners.get(event)||[]).push(fn); }

  emit(event: string, data: T) { this.listeners.get(event)?.forEach(f => f(data)); }

  }

