interface Observer<T> {

  update(data: T): void;

  }

class EventEmitter<T> {

  private observers = new Set<Observer<T>>();

  subscribe(observer: Observer<T>): () => void {

    this.observers.add(observer);

    return () => this.observers.delete(observer); // unsubscribe

  }

  notify(data: T): void {

    this.observers.forEach(o => o.update(data));

  }

  }

// Real-world: Order events

interface OrderEvent { orderId: string; status: string; }

const orderEvents = new EventEmitter<OrderEvent>();

// Multiple observers

const emailObserver: Observer<OrderEvent> = {

  update: ({ orderId, status }) => sendEmail(`Order ${orderId}: ${status}`)

  };

const analyticsObserver: Observer<OrderEvent> = {

  update: (event) => trackEvent('order_status_change', event)

  };

const unsubEmail = orderEvents.subscribe(emailObserver);

orderEvents.subscribe(analyticsObserver);

orderEvents.notify({ orderId: '123', status: 'shipped' });

unsubEmail(); // unsubscribe email

The Observer pattern defines a one-to-many dependency between objects: when a subject changes state, all registered observers are automatically notified and updated.

**Participants: ****Subject (EventEmitter) holds a set of observers; observers implement an update(data) method called on each notification.**

**Use case: ****Event-driven systems — order status changes triggering email notifications and analytics tracking simultaneously.**

**Unsubscribe: ****subscribe() returns an unsubscribe function; call it to remove the observer from the set.**

**Real-world: ****DOM event listeners, RxJS Observables, Node.js EventEmitter, and React state management all use this pattern.**

interface SortStrategy {

  sort(data: number[]): number[];

  }

class BubbleSortStrategy implements SortStrategy {

  sort(data: number[]): number[] {

    const arr = [...data];

    for (let i = 0; i < arr.length; i++)

      for (let j = 0; j < arr.length - i - 1; j++)

        if (arr[j] > arr[j+1]) [arr[j], arr[j+1]] = [arr[j+1], arr[j]];

    return arr;

  }

  }

class QuickSortStrategy implements SortStrategy {

  sort(data: number[]): number[] {

    if (data.length <= 1) return data;

    const pivot = data[0];

    const left  = data.slice(1).filter(x => x <= pivot);

    const right = data.slice(1).filter(x => x > pivot);

    return [...this.sort(left), pivot, ...this.sort(right)];

  }

  }

class Sorter {

  constructor(private strategy: SortStrategy) {}

  setStrategy(strategy: SortStrategy): void { this.strategy = strategy; }

  sort(data: number[]): number[] { return this.strategy.sort(data); }

  }

const sorter = new Sorter(new QuickSortStrategy());

sorter.sort([3,1,4,1,5]);

sorter.setStrategy(new BubbleSortStrategy()); // swap at runtime

The Strategy pattern defines a family of interchangeable algorithms, encapsulates each one in its own class, and allows the algorithm to be swapped at runtime without changing the client.

**Interface: ****SortStrategy defines sort(data): number[] — each concrete strategy (BubbleSortStrategy, QuickSortStrategy) provides its own implementation.**

**Context: ****Sorter holds a strategy reference; setStrategy() swaps algorithms at runtime without altering Sorter's logic.**

**Use case: ****Payment processing (CreditCard, PayPal, Crypto), sorting, compression, and any scenario where behaviour varies by configuration.**

**vs OCP: ****Strategy is a primary way to achieve OCP — new algorithms are new classes, not modifications of the context.**

