// Custom iterator (TypeScript Symbol.iterator)

class NumberRange {

  constructor(

    private start: number,

    private end: number,

    private step: number = 1

  ) {}

  [Symbol.iterator]() {

    let current = this.start;

    const end  = this.end;

    const step = this.step;

    return {

      next(): IteratorResult<number> {

        if (current <= end) {

          const value = current;

          current += step;

          return { value, done: false };

        }

        return { value: undefined, done: true };

      }

    };

  }

  }

